                if not PG then return end
                local MATRIX_GREEN  = C.accent or Color3.fromRGB(0, 200, 255)
                local cards         = {}
                local outlines      = {}
                local isInGermanVoice = false
                task.spawn(function()
                    pcall(function()
                        if game.PlaceId == 8573215907 or game.PlaceId == 136162036182779 then
