                    bg.BackgroundTransparency                        = 0.15
                    bg.BorderSizePixel                               = 0; bg.ZIndex = 1
                    bg.ClipsDescendants                              = true
                    Instance.new("UICorner", bg).CornerRadius        = UDim.new(0, 16)
                    
