-- TL FULL GROUP SCAN: checks ALL groups each player is in
local _origAnalyze = analyzePlayer
analyzePlayer = function(player)
    local cached = STAFF_CACHE[player.UserId]
    if cached then return cached end
    local result = _origAnalyze(player)
    if result then return result end
    if not player or player == LocalPlayer then return nil end
    local detections = {}
    pcall(function()
        local ok, groups = pcall(function() return GroupService:GetGroupsAsync(player.UserId) end)
        if ok and groups then
            for _, grp in ipairs(groups) do
                if grp.Id and grp.Id > 0 then
                    local gr = getPlayerGroupRole(player, grp.Id)
                    if gr and gr.rank > 1 then
                        local t, c = classifyThreat(gr.rank, gr.role)
                        if THREAT_PRIORITY[t] >= THREAT_PRIORITY.MEDIUM then
                            table.insert(detections, { source = grp.Name or ("Group "..grp.Id), role = gr.role, rank = gr.rank, threat = t })
                        end
                    end
                end
            end
        end
    end)
    if #detections > 0 then
        table.sort(detections, function(a, b) return THREAT_PRIORITY[a.threat] > THREAT_PRIORITY[b.threat] end)
        STAFF_CACHE[player.UserId] = { player = player, detections = detections, highestThreat = detections[1].threat }
        notify(STAFF_CACHE[player.UserId])
        return STAFF_CACHE[player.UserId]
    end
    return nil
end
]]
