                    hdrDot.Position               = UDim2.new(0, 0, 0.5, -(_sc.folderHdrH - 16) / 2)
                    hdrDot.BackgroundColor3       = _themePanelColor(accentCol, C.accent)
                    hdrDot.BackgroundTransparency = 0.4
                    hdrDot.BorderSizePixel        = 0
