                            local tHRP = tc and tc:FindFirstChild("HumanoidRootPart")
                            local _lpc = LocalPlayer.Character
                            local myR  = _lpc and _lpc:FindFirstChild("HumanoidRootPart")
                            if not tHRP or not myR then
