                    kbContainer.Position = UDim2.new(0, 0, 0, 26)
                    kbContainer.BackgroundTransparency = 1
                    kbContainer.BorderSizePixel = 0
                    local keybindEntries = {
                        { "Toggle SmartBar", Enum.KeyCode.K, function()
