                    }
                    local totalKbRows = 0
                    for i, entry in ipairs(keybindEntries) do
                        local yPos = (i - 1) * 62
                        if entry[2] == "fixed" then
                            local row = Instance.new("Frame", kbContainer)
                            row.Size = UDim2.new(1, 0, 0, 52)
