                        end)

                        
                        local targetH = isOpen and heightWhenExpanded or 46
                        twP(card, 0.25, { Size = UDim2.new(1, 0, 0, targetH) }, Enum.EasingStyle.Quart,
                            Enum.EasingDirection.Out)

                        
                        local targetRot = isOpen and 180 or 0
