                local _NT_CONFIG = {}

                local function _NT_deepCopy(orig)
                    if type(orig) ~= "table" then return orig end
                    local copy = {}
                    for k, v in pairs(orig) do
                        copy[k] = _NT_deepCopy(v)
                    end
                    return copy
                end

                local function _NT_parseColor(hex)
                    if type(hex) == "string" then return _NT_hexToColor3(hex) end
                    if typeof(hex) == "Color3" then return hex end
                    return Color3.new(1, 1, 1)
                end

                local function _NT_parseTheme(raw)
                    if type(raw) ~= "table" then return nil end
                    local t = {}
                    for _, key in ipairs({"bg", "avatarBg", "avatarText", "divider", "border", "nameText", "roleText"}) do
                        t[key] = raw[key] and _NT_parseColor(raw[key]) or Color3.new(1, 1, 1)
                    end
                    t.bgGradient = raw.bgGradient == true
                    
                    
                    t.bgGradientType = type(raw.bgGradientType) == "string" and raw.bgGradientType or "linear"
                    if type(raw.bgGradientColors) == "table" and #raw.bgGradientColors >= 2 then
                        t.bgGradientColors = {}
                        for _, c in ipairs(raw.bgGradientColors) do t.bgGradientColors[#t.bgGradientColors + 1] = tostring(c) end
                    else
                        t.bgGradientColors = {
                            raw.bgGradientStart and tostring(raw.bgGradientStart) or "#1A1A22",
                            raw.bgGradientEnd and tostring(raw.bgGradientEnd) or "#0E0E18",
                        }
                    end
                    t.bgGradientAngle = tonumber(raw.bgGradientAngle) or tonumber(raw.bgGradientRotation) or 0
                    
                    t.bgGradientStart = t.bgGradientColors[1] and _NT_parseColor(t.bgGradientColors[1]) or t.bg
                    t.bgGradientEnd = t.bgGradientColors[2] and _NT_parseColor(t.bgGradientColors[2]) or t.bg
                    t.bgGradientRotation = t.bgGradientAngle
                    return t
                end

                _NT_loadConfig = function()
                    local success, result = pcall(function()
                        return (game :: any):HttpGet(NAMETAG_CONFIG_URL)
                    end)
                    if not success or not result or result == "" then
                        warn("[NametagConfig] Remote fetch failed — using defaults")
                        return false
                    end
                    
                    local clean = result
                    
                    clean = clean:gsub("^[\239\187\191%s]+", ""):gsub("[%s]+$", "")
                    
                    clean = clean:gsub("^<pre>(.-)</pre>$", "%1")
                    clean = clean:gsub("^<code>(.-)</code>$", "%1")
                    clean = clean:gsub("^<html>.-({.-}).-</html>$", "%1")
                    
                    if not clean:match("^%s*{") then
                        local s, e = clean:find("{.*}")
                        if s then clean = clean:sub(s, e) end
                    end
                    local ok, json = pcall(function() return _SvcHttp:JSONDecode(clean) end)
                    if not ok or type(json) ~= "table" then
                        warn("[NametagConfig] JSON parse failed — using defaults")
                        return false
                    end

                    
                    if type(json.themes) == "table" then
                        for themeName, rawTheme in pairs(json.themes) do
                            local parsed = _NT_parseTheme(rawTheme)
                            if parsed then
                                _NT_CONFIG.themes[themeName] = parsed
                            end
                        end
                    end

                    
                    if type(json.layout) == "table" then
                        for k, v in pairs(json.layout) do
                            if _NT_CONFIG.layout[k] ~= nil then
                                if type(v) == "boolean" then
                                    _NT_CONFIG.layout[k] = v
                                elseif type(v) == "string" then
                                    _NT_CONFIG.layout[k] = v
                                else
                                    _NT_CONFIG.layout[k] = tonumber(v) or _NT_CONFIG.layout[k]
                                end
                            end
                        end
                    end

                    
                    if type(json.layout) == "table" then
                        if type(json.layout.nameFont) == "string" then _NT_CONFIG.layout.nameFont = json.layout.nameFont end
                        if type(json.layout.roleFont) == "string" then _NT_CONFIG.layout.roleFont = json.layout.roleFont end
                    end

                    
                    if type(json.animations) == "table" then
                        for k, v in pairs(json.animations) do
                            if _NT_CONFIG.animations[k] ~= nil then
                                if type(v) == "string" then
                                    _NT_CONFIG.animations[k] = v
                                else
                                    _NT_CONFIG.animations[k] = tonumber(v) or _NT_CONFIG.animations[k]
                                end
                            end
                        end
                    end

                    
                    if type(json.particles) == "table" then
                        for k, v in pairs(json.particles) do
                            if k == "colors" and type(v) == "table" then
                                _NT_CONFIG.particles.colors = v
                            elseif _NT_CONFIG.particles[k] ~= nil then
                                if type(v) == "boolean" then
                                    _NT_CONFIG.particles[k] = v
                                else
                                    _NT_CONFIG.particles[k] = tonumber(v) or _NT_CONFIG.particles[k]
                                end
                            end
                        end
                    end

                    
                    if type(json.roleKeywords) == "table" then
                        for role, keywords in pairs(json.roleKeywords) do
                            if type(keywords) == "table" then
                                _NT_CONFIG.roleKeywords[role] = {}
                                for _, kw in ipairs(keywords) do
                                    table.insert(_NT_CONFIG.roleKeywords[role], tostring(kw):lower())
                                end
                            end
                        end
                    end

                    
                    if type(json.roleUsers) == "table" then
                        for role, users in pairs(json.roleUsers) do
                            if type(users) == "table" then
                                _NT_CONFIG.roleUsers[role] = {}
                                for _, u in ipairs(users) do
                                    table.insert(_NT_CONFIG.roleUsers[role], tostring(u))
                                end
                            end
                        end
                    end

                    
                    if type(json.profilePictures) == "table" then
                        for role, pic in pairs(json.profilePictures) do
                            if type(pic) == "table" then
                                _NT_CONFIG.profilePictures[role] = {
                                    url = pic.url or (_NT_CONFIG.profilePictures[role] and _NT_CONFIG.profilePictures[role].url or ""),
                                    file = pic.file or (_NT_CONFIG.profilePictures[role] and _NT_CONFIG.profilePictures[role].file or ""),
                                }
                            end
                        end
                    end

                    
                    if type(json.customAvatars) == "table" then
                        _NT_CONFIG.customAvatars = {}
                        for username, avatar in pairs(json.customAvatars) do
                            if type(avatar) == "table" then
                                local strokeColor = nil
                                if avatar.strokeStart and avatar.strokeEnd then
                                    strokeColor = ColorSequence.new(
                                        _NT_parseColor(avatar.strokeStart),
                                        _NT_parseColor(avatar.strokeEnd)
                                    )
                                end
                                _NT_CONFIG.customAvatars[username] = {
                                    url = avatar.url or "",
                                    file = avatar.file or "",
                                    strokeColor = strokeColor,
                                }
                            end
                        end
                    end

                    
                    if type(json.tagImages) == "table" then
                        _NT_CONFIG.tagImages = {}
                        for role, img in pairs(json.tagImages) do
                            if type(img) == "table" then
                                _NT_CONFIG.tagImages[role] = {
                                    url = img.url or "",
                                    file = img.file or "",
                                }
                            end
                        end
                    end

                    
                    task.spawn(function()
                        if not _TL_safeIsFolder("assets") then
                            _TL_safeMakeFolder("assets")
                        end
                        if not _TL_safeIsFolder("assets/TL-ROLE-PICS") then pcall(function() _TL_safeMakeFolder("assets/TL-ROLE-PICS") end) end
                        for role, img in pairs(_NT_CONFIG.tagImages) do
                            if img.url and img.url ~= "" and img.file and img.file ~= "" then
                                _TL_expectedAssetFiles[img.file] = { url = img.url, kind = "image" }
                                if not _TL_safeIsFile(img.file) then
                                    local dir = img.file:match("^(.+/)") or ""
                                    if dir ~= "" and not _TL_safeIsFolder(dir) then pcall(function() _TL_safeMakeFolder(dir) end) end
                                    local ok, bytes = pcall(function()
                                        return (game :: any):HttpGet(img.url)
                                    end)
                                    if ok and bytes and bytes ~= "" then
                                        _TL_safeWriteFile(img.file, bytes)
                                    end
                                end
                            end
                        end
                        for role, pic in pairs(_NT_CONFIG.profilePictures) do
                            if pic.url and pic.url ~= "" and pic.file and pic.file ~= "" then
                                _TL_expectedAssetFiles[pic.file] = { url = pic.url, kind = "image" }
                                if not _TL_safeIsFile(pic.file) then
                                    local dir = pic.file:match("^(.+/)") or ""
                                    if dir ~= "" and not _TL_safeIsFolder(dir) then pcall(function() _TL_safeMakeFolder(dir) end) end
                                    local ok, bytes = pcall(function()
                                        return (game :: any):HttpGet(pic.url)
                                    end)
                                    if ok and bytes and bytes ~= "" then
                                        _TL_safeWriteFile(pic.file, bytes)
                                    end
                                end
                            end
                        end
                    end)

                    
                    if type(json.roleLabels) == "table" then
                        _NT_CONFIG.roleLabels = {}
                        for username, label in pairs(json.roleLabels) do
                            if type(label) == "string" and label ~= "" then
                                _NT_CONFIG.roleLabels[username] = label
                            end
                        end
                    end

                    
                    if type(json.displayNames) == "table" then
                        _NT_CONFIG.displayNames = {}
                        for username, name in pairs(json.displayNames) do
                            if type(name) == "string" and name ~= "" then
                                _NT_CONFIG.displayNames[username] = name
                            end
                        end
                    end

                    
                    if type(json.roleDisplayNames) == "table" then
                        _NT_CONFIG.roleDisplayNames = {}
                        for role, label in pairs(json.roleDisplayNames) do
                            if type(label) == "string" and label ~= "" then
                                _NT_CONFIG.roleDisplayNames[role] = label
                            end
                        end
                    end

                    
                    if type(json.enabled) == "boolean" then
                        _NT_CONFIG.enabled = json.enabled
                    end

                    
                    if type(json.targetUser) == "string" then
                        _NT_CONFIG.targetUser = json.targetUser
                    end

                    
                    if type(json.gradients) == "table" then
                        local gradientTargets = {"cardGradient", "avatarGradient", "nameGradient", "roleGradient", "borderGradient"}
                        for _, targetKey in ipairs(gradientTargets) do
                            if type(json.gradients[targetKey]) == "table" then
                                local raw = json.gradients[targetKey]
                                local g = _NT_CONFIG.gradients[targetKey]
                                if g then
                                    if type(raw.enabled) == "boolean" then g.enabled = raw.enabled end
                                    if type(raw.type) == "string" then g.type = raw.type end
                                    if type(raw.rotation) == "number" then g.rotation = raw.rotation end
                                    if type(raw.colors) == "table" and #raw.colors >= 2 then
                                        g.colors = {}
                                        for _, c in ipairs(raw.colors) do g.colors[#g.colors + 1] = tostring(c) end
                                    end
                                    if type(raw.transparency) == "table" and #raw.transparency >= 2 then
                                        g.transparency = {}
                                        for _, t in ipairs(raw.transparency) do g.transparency[#g.transparency + 1] = tonumber(t) or 0 end
                                    end
                                    if type(raw.offset) == "table" and #raw.offset >= 2 then
                                        g.offset = { tonumber(raw.offset[1]) or 0, tonumber(raw.offset[2]) or 0 }
                                    end
                                    if type(raw.thickness) == "number" then g.thickness = raw.thickness end
                                    if type(raw.frequency) == "number" then g.frequency = raw.frequency end
                                    if type(raw.amplitude) == "number" then g.amplitude = raw.amplitude end
                                    if type(raw.speed) == "number" then g.speed = raw.speed end
                                    if type(raw.layers) == "table" then
                                        g.layers = {}
                                        for _, layer in ipairs(raw.layers) do
                                            if type(layer) == "table" then
                                                local l = {}
                                                if type(layer.colors) == "table" then
                                                    l.colors = {}
                                                    for _, c in ipairs(layer.colors) do l.colors[#l.colors + 1] = tostring(c) end
                                                end
                                                if type(layer.transparency) == "table" then
                                                    l.transparency = {}
                                                    for _, t in ipairs(layer.transparency) do l.transparency[#l.transparency + 1] = tonumber(t) or 0 end
                                                end
                                                if type(layer.rotation) == "number" then l.rotation = layer.rotation end
                                                if type(layer.blendMode) == "string" then l.blendMode = layer.blendMode end
                                                g.layers[#g.layers + 1] = l
                                            end
                                        end
                                    end
                                    if type(raw.keyframes) == "table" then
                                        g.keyframes = {}
                                        for _, kf in ipairs(raw.keyframes) do
                                            if type(kf) == "table" then
                                                g.keyframes[#g.keyframes + 1] = {
                                                    time = tonumber(kf.time) or 0,
                                                    colors = type(kf.colors) == "table" and kf.colors or g.colors,
                                                    transparency = type(kf.transparency) == "table" and kf.transparency or g.transparency,
                                                    rotation = tonumber(kf.rotation) or g.rotation,
                                                }
                                            end
                                        end
                                    end
                                end
                            end
                        end
                    end

                    
                    if type(json.userColorOverrides) == "table" then
                        for username, overrides in pairs(json.userColorOverrides) do
                            if type(overrides) == "table" then
                                _NT_CONFIG.userColorOverrides[username] = {}
                                local oc = _NT_CONFIG.userColorOverrides[username]
                                for k, v in pairs(overrides) do
                                    if k ~= "__enabled" then
                                        if type(v) == "string" then
                                            if v == "transparent" then
                                                oc[k] = "transparent"
                                            else
                                                local ok, c = pcall(function() return _NT_parseColor(v) end)
                                                if ok and c then oc[k] = c end
                                            end
                                        end
                                    end
                                end
                                if overrides.__enabled == true then
                                    oc.__enabled = true
                                end
                            end
                        end
                    end

                    if type(json.userGradientOverrides) == "table" then
                        for username, grads in pairs(json.userGradientOverrides) do
                            if type(grads) == "table" then
                                _NT_CONFIG.userGradientOverrides[username] = {}
                                for gradKey, raw in pairs(grads) do
                                    if type(raw) == "table" then
                                        local g = { enabled = false, type = "Linear", colors = {}, transparency = {}, rotation = 0, offset = {0, 0} }
                                        if type(raw.enabled) == "boolean" then g.enabled = raw.enabled end
                                        if type(raw.type) == "string" then g.type = raw.type end
                                        if type(raw.rotation) == "number" then g.rotation = raw.rotation end
                                        if type(raw.colors) == "table" and #raw.colors >= 2 then
                                            for _, c in ipairs(raw.colors) do g.colors[#g.colors + 1] = tostring(c) end
                                        end
                                        if type(raw.transparency) == "table" and #raw.transparency >= 2 then
                                            for _, t in ipairs(raw.transparency) do g.transparency[#g.transparency + 1] = tonumber(t) or 0 end
                                        end
                                        if type(raw.offset) == "table" and #raw.offset >= 2 then
                                            g.offset = { tonumber(raw.offset[1]) or 0, tonumber(raw.offset[2]) or 0 }
                                        end
                                        _NT_CONFIG.userGradientOverrides[username][gradKey] = g
                                    end
                                end
                            end
                        end
                    end

                    return true
                end

                
                _NT_CONFIG = _NT_deepCopy(_NT_DEFAULTS)
                
                
                for _defName, _defTheme in pairs(_NT_CONFIG.themes) do
                    local _parsed = _NT_parseTheme(_defTheme)
                    if _parsed then _NT_CONFIG.themes[_defName] = _parsed end
                end
                _NT_loadConfig()
                _TL_configReady = true
                rawset(_genv, "_TL_configReady", true)

                
                
                if _NT_CONFIG and _NT_CONFIG.roleUsers then
                    local _ADMIN_ROLE_KEYS = { owner = true, admin = true, developer = true }
                    for role, users in pairs(_NT_CONFIG.roleUsers) do
                        if _ADMIN_ROLE_KEYS[role] then
                            for _, u in ipairs(users) do
                                AdminNames[tostring(u)] = true
                            end
                        end
                    end
                end

                
                
                
                local _GRADIENT_TYPES = {
                    "Linear", "Radial", "Conic", "Angular", "Mesh",
                    "Color", "Blend", "Duotone", "Multicolor", "Smooth",
                    "Soft", "Glass", "Neon", "Metallic", "Iridescent",
                    "Holographic", "Aurora", "Sunset", "Spectrum", "Liquid",
                    "Dynamic", "Fluid", "Chromatic", "Ombre", "Fade",
                    "ColorTransition", "Overlay", "Flow", "Wave",
                }

                local _NT_GRADIENT_ANIM_CONNS = {}
                local _NT_GRADIENT_ANIM_ALIVE = {}
                local _NT_GRADIENT_MAX_ANIM = 60 
                local _NT_GRADIENT_ANIM_INTERVAL = 0.05 

                local function _NT_stopGradientAnims(parent)
                    for i = #_NT_GRADIENT_ANIM_ALIVE, 1, -1 do
                        if _NT_GRADIENT_ANIM_ALIVE[i] and _NT_GRADIENT_ANIM_ALIVE[i].parent == parent then
                            _NT_GRADIENT_ANIM_ALIVE[i].alive = false
                            table.remove(_NT_GRADIENT_ANIM_ALIVE, i)
                        end
                    end
                    if _NT_GRADIENT_ANIM_CONNS[parent] then
                        for _, c in ipairs(_NT_GRADIENT_ANIM_CONNS[parent]) do
                            pcall(function() c:Disconnect() end)
                        end
                        _NT_GRADIENT_ANIM_CONNS[parent] = nil
                    end
                end

                local function _NT_canAnimateGradient()
                    return #_NT_GRADIENT_ANIM_ALIVE < _NT_GRADIENT_MAX_ANIM
                end

                local function _NT_buildColorSeq(colors, transparencies)
                    if type(colors) ~= "table" or #colors < 2 then
                        return ColorSequence.new(Color3.new(1, 1, 1)), NumberSequence.new(0)
                    end
                    local csPairs, nsPairs = {}, {}
                    for i = 1, #colors do
                        local t = (i - 1) / math.max(1, #colors - 1)
                        csPairs[#csPairs + 1] = ColorSequenceKeypoint.new(t, _NT_parseColor(colors[i]))
                        local tr = (type(transparencies) == "table" and transparencies[i]) or 0
                        nsPairs[#nsPairs + 1] = NumberSequenceKeypoint.new(t, math.clamp(tonumber(tr) or 0, 0, 1))
                    end
                    return ColorSequence.new(csPairs), NumberSequence.new(nsPairs)
                end

                local function _NT_applyGradient(target, gradCfg)
                    if not target or not gradCfg or not gradCfg.enabled then return nil, {} end
                    
                    local _GRAD_TYPE_MAP = {
                        linear = "Linear", radial = "Radial", conic = "Conic", angular = "Angular",
                        mesh = "Mesh", color = "Color", blend = "Blend", colorblend = "Blend",
                        duotone = "Duotone", multicolor = "Multicolor", smooth = "Smooth",
                        soft = "Soft", glass = "Glass", neon = "Neon", metallic = "Metallic",
                        iridescent = "Iridescent", holographic = "Holographic", aurora = "Aurora",
                        sunset = "Sunset", spectrum = "Spectrum", liquid = "Liquid",
                        dynamic = "Dynamic", fluid = "Fluid", chromatic = "Chromatic",
                        ombre = "Ombre", fade = "Fade", transition = "ColorTransition",
                        colortransition = "ColorTransition", overlay = "Overlay",
                        gradmesh = "Mesh", flow = "Flow", wave = "Wave",
                    }
                    local rawType = tostring(gradCfg.type or "Linear"):lower()
                    local gType = _GRAD_TYPE_MAP[rawType] or "Linear"
                    local colors = gradCfg.colors or { "#FFFFFF", "#000000" }
                    local trans = gradCfg.transparency or { 0, 0 }
                    local rot = tonumber(gradCfg.rotation) or 0
                    local cs, ns = _NT_buildColorSeq(colors, trans)
                    local conns = {}

                    if gType == "Linear" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs; ug.Transparency = ns
                        ug.Rotation = rot
                        ug.Offset = Vector2.new(gradCfg.offset and gradCfg.offset[1] or 0, gradCfg.offset and gradCfg.offset[2] or 0)
                        return ug, conns

                    elseif gType == "Radial" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs; ug.Transparency = ns
                        ug.Rotation = rot; ug.Style = Enum.GradientStyle.Radial
                        return ug, conns

                    elseif gType == "Conic" or gType == "Angular" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs; ug.Transparency = ns
                        ug.Rotation = rot; ug.Style = Enum.GradientStyle.Radial
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.5
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function() ug.Rotation = (rot + t * speed * 360) % 360 end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Mesh" then
                        local layers = gradCfg.layers
                        if type(layers) ~= "table" or #layers == 0 then
                            layers = {
                                { colors = colors, transparency = trans, rotation = rot },
                                { colors = { colors[#colors] or "#000000", colors[1] or "#FFFFFF" }, transparency = { 0.5, 0.5 }, rotation = (rot + 90) % 360 },
                            }
                        end
                        for _, layer in ipairs(layers) do
                            local lcs, lns = _NT_buildColorSeq(layer.colors, layer.transparency)
                            local lug = Instance.new("UIGradient", target)
                            lug.Color = lcs; lug.Transparency = lns
                            lug.Rotation = layer.rotation or rot
                            lug.Offset = Vector2.new(0.5, 0.5)
                        end
                        return nil, conns

                    elseif gType == "Color" or gType == "ColorTransition" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs; ug.Transparency = ns
                        ug.Rotation = rot; ug.Style = Enum.GradientStyle.Linear
                        return ug, conns

                    elseif gType == "Blend" then
                        local ug = Instance.new("UIGradient", target)
                        local blendT = gradCfg.transparency or { 0, 0.5 }
                        local blendNS = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, math.clamp(blendT[1] or 0, 0, 0.9)),
                            NumberSequenceKeypoint.new(0.5, math.clamp(blendT[2] or 0.3, 0, 0.9)),
                            NumberSequenceKeypoint.new(1, math.clamp(blendT[1] or 0, 0, 0.9)),
                        })
                        ug.Color = cs; ug.Transparency = blendNS
                        ug.Rotation = rot
                        return ug, conns

                    elseif gType == "Duotone" then
                        local c1 = _NT_parseColor(colors[1] or "#FFFFFF")
                        local c2 = _NT_parseColor(colors[2] or "#000000")
                        target.BackgroundColor3 = c1
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = ColorSequence.new(c2, c1)
                        ug.Transparency = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, 0),
                            NumberSequenceKeypoint.new(0.5, 0.3),
                            NumberSequenceKeypoint.new(1, 0),
                        })
                        ug.Rotation = rot
                        return ug, conns

                    elseif gType == "Multicolor" or gType == "Spectrum" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs; ug.Transparency = ns
                        ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.3
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function() ug.Rotation = (rot + t * speed * 120) % 360 end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Smooth" then
                        local smoothT = trans
                        if #smoothT == 2 then
                            smoothT = { smoothT[1], (smoothT[1] + smoothT[2]) / 2, smoothT[2] }
                        end
                        local smoothCS = {}
                        for i = 1, #colors do
                            local t = (i - 1) / math.max(1, #colors - 1)
                            smoothCS[#smoothCS + 1] = ColorSequenceKeypoint.new(t, _NT_parseColor(colors[i]))
                        end
                        if #smoothCS == 2 then
                            local mid = _NT_parseColor(colors[1]):Lerp(_NT_parseColor(colors[2]), 0.5)
                            smoothCS = {
                                ColorSequenceKeypoint.new(0, _NT_parseColor(colors[1])),
                                ColorSequenceKeypoint.new(0.5, mid),
                                ColorSequenceKeypoint.new(1, _NT_parseColor(colors[2])),
                            }
                        end
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = ColorSequence.new(smoothCS)
                        ug.Transparency = ns; ug.Rotation = rot
                        return ug, conns

                    elseif gType == "Soft" then
                        local ug = Instance.new("UIGradient", target)
                        local softColors = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i]):Lerp(Color3.new(1, 1, 1), 0.25)
                            softColors[#softColors + 1] = ColorSequenceKeypoint.new((i - 1) / math.max(1, #colors - 1), c)
                        end
                        ug.Color = ColorSequence.new(softColors)
                        ug.Transparency = ns; ug.Rotation = rot
                        ug.Style = Enum.GradientStyle.Radial
                        return ug, conns

                    elseif gType == "Glass" then
                        local ug = Instance.new("UIGradient", target)
                        local glassNS = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, 0.3),
                            NumberSequenceKeypoint.new(0.3, 0),
                            NumberSequenceKeypoint.new(0.6, 0.15),
                            NumberSequenceKeypoint.new(1, 0.5),
                        })
                        ug.Color = cs; ug.Transparency = glassNS
                        ug.Rotation = rot + 45
                        return ug, conns

                    elseif gType == "Neon" then
                        local ug = Instance.new("UIGradient", target)
                        local neonCS = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i])
                            local brightC = c:Lerp(Color3.new(1, 1, 1), 0.6)
                            local t1 = (i - 1) / #colors
                            local t2 = (i - 0.5) / #colors
                            neonCS[#neonCS + 1] = ColorSequenceKeypoint.new(t1, brightC)
                            neonCS[#neonCS + 1] = ColorSequenceKeypoint.new(t2, c)
                        end
                        neonCS[#neonCS + 1] = ColorSequenceKeypoint.new(1, neonCS[1].Value)
                        ug.Color = ColorSequence.new(neonCS)
                        ug.Transparency = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, 0),
                            NumberSequenceKeypoint.new(0.25, 0.1),
                            NumberSequenceKeypoint.new(0.5, 0),
                            NumberSequenceKeypoint.new(0.75, 0.1),
                            NumberSequenceKeypoint.new(1, 0),
                        })
                        ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 1
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function() ug.Rotation = (rot + t * speed * 60) % 360 end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Metallic" then
                        local ug = Instance.new("UIGradient", target)
                        local metCS = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i])
                            local metDark = c:Lerp(Color3.new(0, 0, 0), 0.5)
                            local metLight = c:Lerp(Color3.new(1, 1, 1), 0.4)
                            local t1 = (i - 1) / #colors
                            local t2 = (i - 0.5) / #colors
                            metCS[#metCS + 1] = ColorSequenceKeypoint.new(t1, metDark)
                            metCS[#metCS + 1] = ColorSequenceKeypoint.new(t2, metLight)
                        end
                        metCS[#metCS + 1] = ColorSequenceKeypoint.new(1, metCS[1].Value)
                        ug.Color = ColorSequence.new(metCS)
                        ug.Transparency = ns; ug.Rotation = rot
                        return ug, conns

                    elseif gType == "Iridescent" or gType == "Holographic" then
                        local ug = Instance.new("UIGradient", target)
                        local iriCS = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i])
                            local brightC = c:Lerp(Color3.new(1, 1, 1), 0.35)
                            local t = (i - 1) / math.max(1, #colors - 1)
                            iriCS[#iriCS + 1] = ColorSequenceKeypoint.new(t, brightC)
                        end
                        if #iriCS < 3 then
                            local mid = _NT_parseColor(colors[1]):Lerp(_NT_parseColor(colors[2] or colors[1]), 0.5)
                            iriCS = {
                                ColorSequenceKeypoint.new(0, _NT_parseColor(colors[1]):Lerp(Color3.new(1,1,1), 0.35)),
                                ColorSequenceKeypoint.new(0.5, mid:Lerp(Color3.new(1,1,1), 0.35)),
                                ColorSequenceKeypoint.new(1, _NT_parseColor(colors[2] or colors[1]):Lerp(Color3.new(1,1,1), 0.35)),
                            }
                        end
                        ug.Color = ColorSequence.new(iriCS)
                        ug.Transparency = ns; ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.4
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function() ug.Rotation = (rot + t * speed * 90) % 360 end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Aurora" then
                        local ug = Instance.new("UIGradient", target)
                        local auCS = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i])
                            local t = (i - 1) / math.max(1, #colors - 1)
                            auCS[#auCS + 1] = ColorSequenceKeypoint.new(t, c)
                        end
                        if #auCS < 3 then
                            local c1 = _NT_parseColor(colors[1])
                            local c2 = _NT_parseColor(colors[2] or colors[1])
                            local mid = c1:Lerp(c2, 0.5)
                            auCS = {
                                ColorSequenceKeypoint.new(0, c1),
                                ColorSequenceKeypoint.new(0.5, mid),
                                ColorSequenceKeypoint.new(1, c2),
                            }
                        end
                        ug.Color = ColorSequence.new(auCS)
                        ug.Transparency = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, 0.1),
                            NumberSequenceKeypoint.new(0.3, 0),
                            NumberSequenceKeypoint.new(0.7, 0),
                            NumberSequenceKeypoint.new(1, 0.1),
                        })
                        ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.3
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function() ug.Rotation = (rot + t * speed * 50) % 360 end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Sunset" then
                        local ug = Instance.new("UIGradient", target)
                        local ssCS = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i])
                            local t = (i - 1) / math.max(1, #colors - 1)
                            ssCS[#ssCS + 1] = ColorSequenceKeypoint.new(t, c)
                        end
                        ug.Color = ColorSequence.new(ssCS)
                        ug.Transparency = ns; ug.Rotation = rot
                        return ug, conns

                    elseif gType == "Liquid" or gType == "Fluid" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs
                        ug.Style = Enum.GradientStyle.Radial
                        ug.Transparency = ns; ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.5
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function()
                                    ug.Rotation = (rot + math.sin(t * speed) * 45) % 360
                                    ug.Offset = Vector2.new(math.sin(t * speed * 0.7) * 0.15, math.cos(t * speed * 0.5) * 0.15)
                                end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Dynamic" or gType == "Flow" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs; ug.Transparency = ns; ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 1
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function()
                                    ug.Rotation = (rot + t * speed * 30) % 360
                                    ug.Offset = Vector2.new(math.sin(t * speed * 0.4) * 0.2, 0)
                                end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Chromatic" then
                        local ug = Instance.new("UIGradient", target)
                        local chCS = {}
                        for i = 1, #colors do
                            local c = _NT_parseColor(colors[i])
                            chCS[#chCS + 1] = ColorSequenceKeypoint.new((i - 1) / math.max(1, #colors - 1), c)
                        end
                        if #chCS < 3 then
                            local extra = _NT_parseColor(colors[1] or "#FFFFFF"):Lerp(_NT_parseColor(colors[2] or "#000000"), 0.5)
                            table.insert(chCS, 2, ColorSequenceKeypoint.new(0.5, extra))
                        end
                        ug.Color = ColorSequence.new(chCS)
                        ug.Transparency = ns; ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.6
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function()
                                    local shift = (t * speed * 0.3) % 1
                                    ug.Offset = Vector2.new(shift - 0.5, 0)
                                end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Ombre" or gType == "Fade" then
                        local ug = Instance.new("UIGradient", target)
                        local oC1 = _NT_parseColor(colors[1] or "#000000")
                        local oC2 = _NT_parseColor(colors[2] or "#FFFFFF")
                        ug.Color = ColorSequence.new(oC1, oC1, oC2, oC2)
                        ug.Transparency = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, 0),
                            NumberSequenceKeypoint.new(0.4, 0),
                            NumberSequenceKeypoint.new(0.6, 0.4),
                            NumberSequenceKeypoint.new(1, 0.8),
                        })
                        ug.Rotation = rot
                        return ug, conns

                    elseif gType == "Wave" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs
                        local waveNS = {}
                        local freq = gradCfg.frequency or 4
                        local amp = gradCfg.amplitude or 0.3
                        for i = 0, 10 do
                            local t = i / 10
                            local baseT = trans[1] or 0
                            waveNS[#waveNS + 1] = NumberSequenceKeypoint.new(t, baseT + amp * math.abs(math.sin(t * freq * math.pi)))
                        end
                        ug.Transparency = NumberSequence.new(waveNS)
                        ug.Rotation = rot
                        if not _NT_canAnimateGradient() then return ug, conns end
                        local alive = { alive = true, parent = target }
                        _NT_GRADIENT_ANIM_ALIVE[#_NT_GRADIENT_ANIM_ALIVE + 1] = alive
                        local speed = gradCfg.speed or 0.5
                        task.spawn(function()
                            local t = 0
                            while alive.alive and target and target.Parent do
                                t = t + task.wait(_NT_GRADIENT_ANIM_INTERVAL)
                                pcall(function() ug.Offset = Vector2.new(math.sin(t * speed) * 0.2, 0) end)
                            end
                        end)
                        return ug, conns

                    elseif gType == "Overlay" then
                        local ug = Instance.new("UIGradient", target)
                        ug.Color = cs
                        ug.Transparency = NumberSequence.new({
                            NumberSequenceKeypoint.new(0, 0.2),
                            NumberSequenceKeypoint.new(0.5, 0),
                            NumberSequenceKeypoint.new(1, 0.2),
                        })
                        ug.Rotation = rot + 45
                        return ug, conns
                    end

                    return nil, conns
                end

                local function _NT_applyAllGradients(billboard, card, avatar, nameLabel, roleTxt, cardBorder, gradCfg)
                    if type(gradCfg) ~= "table" then return end
                    if gradCfg.cardGradient and gradCfg.cardGradient.enabled then
                        _NT_applyGradient(card, gradCfg.cardGradient)
                    end
                    if gradCfg.avatarGradient and gradCfg.avatarGradient.enabled then
                        _NT_applyGradient(avatar, gradCfg.avatarGradient)
                    end
                    if gradCfg.nameGradient and gradCfg.nameGradient.enabled then
                        _NT_applyGradient(nameLabel, gradCfg.nameGradient)
                    end
                    if gradCfg.roleGradient and gradCfg.roleGradient.enabled then
                        _NT_applyGradient(roleTxt, gradCfg.roleGradient)
                    end
                    if gradCfg.borderGradient and gradCfg.borderGradient.enabled and cardBorder then
                        _NT_applyGradient(cardBorder, gradCfg.borderGradient)
                    end
                end

                local creatingNametag = {}
                local function CreateCustomNametag(character, playerName, isAdmin)
                    if not character then return end
                    if creatingNametag[playerName] then return end
                    creatingNametag[playerName] = true

                    local player = Players:FindFirstChild(playerName)
                    local playerUserId = player and tostring(player.UserId) or nil

                    local override = NameOverrides[playerName]
                    if not override and playerUserId then
                        override = NameOverrides[playerUserId]
                    end

                    local displayName  = _NT_CONFIG.displayNames and _NT_CONFIG.displayNames[playerName]
                        or (override and override.display or playerName)
                    local roleLabel    = _NT_CONFIG.roleLabels and _NT_CONFIG.roleLabels[playerName]
                        or (override and override.role or nil)

                    
                    local roleLower    = (roleLabel or (isAdmin and "TL Admin" or "TL User")):lower()
                    local displayLower = (override and override.display or ""):lower()
                    local themeKey     = "user"

                    
                    
                    local _NT_ROLE_PRIO = { owner=7, developer=6, admin=5, moderator=4, staff=3, advertising=2, user=1 }
                    local _ntHighestPrio = 0
                    for role, users in pairs(_NT_CONFIG.roleUsers) do
                        for _, u in ipairs(users) do
                            if u:lower() == playerName:lower() then
                                local prio = _NT_ROLE_PRIO[role] or 0
                                if prio > _ntHighestPrio then
                                    _ntHighestPrio = prio
                                    themeKey = role
                                end
                                break
                            end
                        end
                    end

                    
                    if themeKey == "user" then
                        for tk, keywords in pairs(_NT_CONFIG.roleKeywords) do
                            if themeKey == "user" then
                                for _, kw in ipairs(keywords) do
                                    if roleLower:find(kw) or displayLower:find(kw) then
                                        themeKey = tk
                                        break
                                    end
                                end
                            end
                        end
                    end

                    
                    if themeKey == "user" and isAdmin then
                        themeKey = "admin"
                    end

                    
                    if themeKey == "user" and displayName == playerName and player then
                        local robloxDisplayName = player:FindFirstChild("DisplayName")
                        if robloxDisplayName and robloxDisplayName.Value ~= "" then
                            displayName = robloxDisplayName.Value
                        end
                    end

                    
                    
                    
                    
                    
                    if not roleLabel then
                        local _NT_ROLE_DEFAULTS = { user="TL User", admin="TL Admin", owner="TL Owner", developer="TL Developer", advertising="TL Advertising", moderator="TL Moderator" }
                        roleLabel = (_NT_CONFIG.roleDisplayNames and _NT_CONFIG.roleDisplayNames[themeKey])
                            or _NT_ROLE_DEFAULTS[themeKey]
                            or "TL User"
                    end

                    local theme = _NT_CONFIG.themes[themeKey] or _NT_DEFAULTS.themes.user
                    local customAvatar = _NT_CONFIG.customAvatars[playerName] or customUserAvatars[playerName]

                    
                    local _userColorOvr = _NT_CONFIG.userColorOverrides and _NT_CONFIG.userColorOverrides[playerName]
                    if _userColorOvr and _userColorOvr.__enabled then
                        theme = _NT_deepCopy(theme)
                        for k, v in pairs(_userColorOvr) do
                            if k ~= "__enabled" and v ~= nil then
                                if v == "transparent" then
                                    theme[k] = Color3.new(1, 1, 1)
                                    theme[k .. "_transparent"] = true
                                else
                                    theme[k] = v
                                end
                            end
                        end
                    end

                    
                    local _userGradOvr = _NT_CONFIG.userGradientOverrides and _NT_CONFIG.userGradientOverrides[playerName]
                    local _savedGrads = nil
                    if _userGradOvr then
                        _savedGrads = _NT_deepCopy(_NT_CONFIG.gradients)
                        for gradKey, gradData in pairs(_userGradOvr) do
                            if _NT_CONFIG.gradients[gradKey] then
                                _NT_CONFIG.gradients[gradKey] = _NT_deepCopy(gradData)
                            end
                        end
                    end

                    local head = character:WaitForChild("Head", 5)
                    if not head then
                        creatingNametag[playerName] = nil; return
                    end

                    local guiParentBB = CoreGui
                    local existingBB  = guiParentBB:FindFirstChild("CovertPeerTag_" .. playerName)
                    if existingBB then existingBB:Destroy() end

                    local billboard             = Instance.new("BillboardGui")
                    billboard.Name              = "CovertPeerTag_" .. playerName
                    billboard.Adornee           = head
