                    s.ScrollBarImageColor3 = C.accent
                    s.Active = true
                    s.ClipsDescendants = true
                    s.ScrollingDirection = Enum.ScrollingDirection.Y
                    for k, v in pairs(props) do s[k] = v end
                    if parent then s.Parent = parent end
                    return s
                end

                            
            
            

