                            local _oax, _oxsc, _oxoff = getPanelXAnchor()
                            old.AnchorPoint = Vector2.new(_oax, 1)
                            local oldTargetPos = UDim2.new(_oxsc, _oxoff, PANEL_HIDE.Y.Scale, PANEL_HIDE.Y.Offset + 10)
                            tw(old, 0.16, {
